const crypto = require('crypto');

// IMPORTANT: You must store your Razorpay Key Secret securely.
// For now, we will hardcode it. Later, this should be moved to n8n credentials.
const RAZORPAY_KEY_SECRET = '0hEAxWBC7vTeLOK974B442ZD'; // <-- PASTE YOUR KEY SECRET HERE

// Razorpay sends all the data in the query parameters of the webhook URL.
const queryParams = $request.query;

const paymentLinkId = queryParams.razorpay_payment_link_id;
const paymentId = queryParams.razorpay_payment_id;
const paymentLinkRefId = queryParams.razorpay_payment_link_reference_id; // This is our order_id
const paymentLinkStatus = queryParams.razorpay_payment_link_status;
const signature = queryParams.razorpay_signature;

// The string that needs to be signed is a combination of these IDs.
const body = `${paymentLinkId}|${paymentLinkRefId}|${paymentLinkStatus}|${paymentId}`;

// Create the HMAC signature using SHA256 and your secret key.
const expectedSignature = crypto
  .createHmac('sha256', RAZORPAY_KEY_SECRET)
  .update(body.toString())
  .digest('hex');

// Compare our calculated signature with the one from Razorpay.
if (expectedSignature === signature) {
  // SUCCESS: The request is authentic. Pass the data on.
  return [{
    json: {
      status: 'success_verified',
      order_id: paymentLinkRefId, // Pass the order_id for the next steps
      payment_id: paymentId
    }
  }];
} else {
  // FAILURE: The signature is invalid. This is a potential security risk.
  // We must stop the workflow here.
  console.error("CRITICAL: Invalid Razorpay signature. Request will be ignored.");
  // Returning an empty array effectively stops this branch of the workflow.
  return []; 
}

// The input is an array of two items from the Merge node.
const mergedItems = $items();

// --- Find the two pieces of data we need ---
const webhookData = mergedItems.find(item => item.json.query?.razorpay_signature)?.json;
const dbData = mergedItems.find(item => item.json.order_details_json)?.json;

if (!webhookData || !dbData) {
  throw new Error("FATAL: Webhook or DB data was lost after the merge.");
}

const orderId = webhookData.query.razorpay_payment_link_reference_id;
const orderDetails = dbData.order_details_json;

if (!orderDetails || !orderDetails.items_in_final_order) {
    throw new Error("FATAL: 'items_in_final_order' is missing from the stored JSON.");
}

const escape = (str) => str ? String(str).replace(/'/g, "''") : 'NULL';

// --- THE FIX IS HERE ---
// Added 'order_created_at' to the column list and 'NOW()' to the VALUES list.
const summaryInsert = `
INSERT INTO n8n.order_summary (
    order_id, chat_id, store_id, shipping_address, 
    subtotal_before_discounts, total_discount_applied, final_order_total, 
    applied_order_level_promo_ids, order_created_at
)
VALUES (
    '${escape(orderId)}', 
    ${orderDetails.chat_id}, 
    ${orderDetails.store_id || 'NULL'}, 
    '${escape(orderDetails.address)}', 
    ${orderDetails.subtotal_before_discounts}, 
    ${orderDetails.total_discount_applied}, 
    ${orderDetails.final_order_total}, 
    '${escape(orderDetails.applied_promo_id)}',
    NOW()
);
`;
// --- END OF FIX ---

const itemValues = orderDetails.items_in_final_order.map(item =>
  `('${escape(orderId)}', ${orderDetails.chat_id}, '${escape(item.original_name)}', ${item.quantity}, 'pending_confirmation', '${escape(item.sku)}', ${parseFloat(item.unit_price) || 0})`
).join(',');

const itemsInsert = `
INSERT INTO n8n.orders (order_id, user_id, name, quantity, status, sku, unit_price)
VALUES ${itemValues};
`;

const stockUpdates = orderDetails.items_in_final_order.map(item =>
  `UPDATE n8n.inventory SET stock = stock - ${item.quantity} WHERE sku = '${escape(item.sku)}';`
).join('\n');

const cleanupPendingOrder = `
DELETE FROM n8n.pending_orders WHERE order_id = '${escape(orderId)}';
`;

const finalSqlScript = `
BEGIN;
${summaryInsert}
${itemsInsert}
${stockUpdates}
${cleanupPendingOrder}
COMMIT;
`;

return [{
  json: {
    sql_script: finalSqlScript,
    ...orderDetails
  }
}];

function escapeMarkdownV2(text) {
  const str = String(text || '');
  return str
    .replace(/\\/g, '\\\\')
    .replace(/([_*[\]()~`>#+\-=|{}.!])/g, '\\$1');
}

// Get final order data from previous node
const finalOrderData = $items("Get Final Order Data")[0].json;

const orderId = finalOrderData.order_id.trim();
const chatId = finalOrderData.chat_id;
const totalPaid = parseFloat(finalOrderData.final_order_total).toFixed(2);

// Build the message using proper escaping for all dynamic and static text
const message = 
  `✅ *${escapeMarkdownV2('Payment Received!')}*\n\n` +
  `${escapeMarkdownV2('Thank you for your payment of')} *₹${escapeMarkdownV2(totalPaid)}*${escapeMarkdownV2('.')} \n\n` +
  `${escapeMarkdownV2('Your Order')} *\\#${escapeMarkdownV2(orderId)}* ${escapeMarkdownV2('is now confirmed and has been sent to the store. We\'ll notify you again once it\'s on its way!')}`;

return [{
  json: {
    confirmation_message: message,
    chat_id_to_use: chatId,
    parse_mode: 'MarkdownV2'
  }
}];
